SELECT COUNT(*) FROM hits;
SELECT COUNT(*) FROM hits WHERE AdvEngineID <> 0;
SELECT SUM(AdvEngineID), COUNT(*), AVG(ResolutionWidth) FROM hits;
SELECT AVG(UserID) FROM hits;
SELECT COUNT(DISTINCT UserID) FROM hits;
SELECT COUNT(DISTINCT SearchPhrase) FROM hits;
SELECT MIN(EventDate), MAX(EventDate) FROM hits;
SELECT AdvEngineID, COUNT(*) FROM hits WHERE AdvEngineID <> 0 GROUP BY AdvEngineID ORDER BY COUNT(*) DESC;
SELECT TOP 10 RegionID, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY RegionID ORDER BY u DESC;
SELECT TOP 10 RegionID, SUM(AdvEngineID), COUNT(*) AS c, AVG(ResolutionWidth), COUNT(DISTINCT UserID) FROM hits GROUP BY RegionID ORDER BY c DESC;
SELECT TOP 10 MobilePhoneModel, COUNT(DISTINCT UserID) AS u FROM hits WHERE MobilePhoneModel <> '' GROUP BY MobilePhoneModel ORDER BY u DESC;
SELECT TOP 10 MobilePhone, MobilePhoneModel, COUNT(DISTINCT UserID) AS u FROM hits WHERE MobilePhoneModel <> '' GROUP BY MobilePhone, MobilePhoneModel ORDER BY u DESC;
SELECT TOP 10 SearchPhrase, COUNT(*) AS c FROM hits WHERE SearchPhrase <> '' GROUP BY SearchPhrase ORDER BY c DESC;
SELECT TOP 10 SearchPhrase, COUNT(DISTINCT UserID) AS u FROM hits WHERE SearchPhrase <> '' GROUP BY SearchPhrase ORDER BY u DESC;
SELECT TOP 10 SearchEngineID, SearchPhrase, COUNT(*) AS c FROM hits WHERE SearchPhrase <> '' GROUP BY SearchEngineID, SearchPhrase ORDER BY c DESC;
SELECT TOP 10 UserID, COUNT(*) FROM hits GROUP BY UserID ORDER BY COUNT(*) DESC;
SELECT TOP 10 UserID, SearchPhrase, COUNT(*) FROM hits GROUP BY UserID, SearchPhrase ORDER BY COUNT(*) DESC;
SELECT TOP 10 UserID, SearchPhrase, COUNT(*) FROM hits GROUP BY UserID, SearchPhrase;
SELECT TOP 10 UserID, DATEPART(minute, EventTime) AS m, SearchPhrase, COUNT(*) FROM hits GROUP BY UserID, DATEPART(minute, EventTime), SearchPhrase ORDER BY COUNT(*) DESC;
SELECT UserID FROM hits WHERE UserID = 435090932899640449;
SELECT COUNT(*) FROM hits WHERE URL LIKE '%google%';
SELECT TOP 10 SearchPhrase, MIN(URL), COUNT(*) AS c FROM hits WHERE URL LIKE '%google%' AND SearchPhrase <> '' GROUP BY SearchPhrase ORDER BY c DESC;
SELECT TOP 10 SearchPhrase, MIN(URL), MIN(Title), COUNT(*) AS c, COUNT(DISTINCT UserID) FROM hits WHERE Title LIKE '%Google%' AND URL NOT LIKE '%.google.%' AND SearchPhrase <> '' GROUP BY SearchPhrase ORDER BY c DESC;
SELECT TOP 10 * FROM hits WHERE URL LIKE '%google%' ORDER BY EventTime;
SELECT TOP 10 SearchPhrase FROM hits WHERE SearchPhrase <> '' ORDER BY EventTime;
SELECT TOP 10 SearchPhrase FROM hits WHERE SearchPhrase <> '' ORDER BY SearchPhrase;
SELECT TOP 10 SearchPhrase FROM hits WHERE SearchPhrase <> '' ORDER BY EventTime, SearchPhrase;
SELECT TOP 25 CounterID, AVG(CAST(LEN(URL) AS BIGINT)) AS l, COUNT(*) AS c FROM hits WHERE URL <> '' GROUP BY CounterID HAVING COUNT(*) > 100000 ORDER BY l DESC;
SELECT TOP 25 SUBSTRING(r, CHARINDEX('://', r) + 3, CHARINDEX('/', r + '/', CHARINDEX('://', r) + 3) - (CHARINDEX('://', r) + 3)) AS k, AVG(CAST(LEN(Referer) AS BIGINT)) AS l, COUNT(*) AS c, MIN(Referer) AS m FROM (SELECT Referer, REPLACE(Referer, '://www.', '://') AS r FROM hits WHERE Referer <> '') x GROUP BY SUBSTRING(r, CHARINDEX('://', r) + 3, CHARINDEX('/', r + '/', CHARINDEX('://', r) + 3) - (CHARINDEX('://', r) + 3)) HAVING COUNT(*) > 100000 ORDER BY l DESC;
